"use strict";
(function () {
	function readCookie(name) {
		try {
			var key = name + "=";
			var parts = document.cookie ? document.cookie.split(";") : [];
			for (var i = 0; i < parts.length; i++) {
				var chunk = parts[i].trim();
				if (chunk.indexOf(key) === 0) {
					return chunk.substring(key.length);
				}
			}
		} catch (e) {
		}
		return "";
	}

	function getServerPrefs() {
		try {
			var raw = readCookie("biotern_theme_preferences");
			if (!raw) return null;
			var decoded = decodeURIComponent(raw);
			var parsed = JSON.parse(decoded);
			if (parsed && typeof parsed === "object") {
				return parsed;
			}
		} catch (e) {
		}
		return null;
	}

	function safeGet(key) {
		try {
			return localStorage.getItem(key);
		} catch (e) {
			return null;
		}
	}

	function safeSet(key, value) {
		try {
			localStorage.setItem(key, value);
		} catch (e) {
		}
	}

	function safeRemove(key) {
		try {
			localStorage.removeItem(key);
		} catch (e) {
		}
	}

	function getAllowedFonts() {
		return [
			"app-font-family-inter",
			"app-font-family-lato",
			"app-font-family-rubik",
			"app-font-family-cinzel",
			"app-font-family-nunito",
			"app-font-family-roboto",
			"app-font-family-ubuntu",
			"app-font-family-poppins",
			"app-font-family-raleway",
			"app-font-family-system-ui",
			"app-font-family-noto-sans",
			"app-font-family-fira-sans",
			"app-font-family-work-sans",
			"app-font-family-open-sans",
			"app-font-family-montserrat",
			"app-font-family-maven-pro",
			"app-font-family-quicksand",
			"app-font-family-josefin-sans",
			"app-font-family-ibm-plex-sans",
			"app-font-family-source-sans-pro",
			"app-font-family-montserrat-alt",
			"app-font-family-roboto-slab"
		];
	}

	function clearFontClasses() {
		try {
			var classes = document.documentElement.className || "";
			document.documentElement.className = classes.replace(/\bapp-font-family-[^\s]+\b/g, "").replace(/\s{2,}/g, " ").trim();
		} catch (e) {
		}
	}

	function getFontMode() {
		var allowedFonts = getAllowedFonts();

		var serverPrefs = getServerPrefs();
		if (serverPrefs && typeof serverPrefs.font === "string") {
			if (serverPrefs.font === "default") return "default";
			if (allowedFonts.indexOf(serverPrefs.font) !== -1) return serverPrefs.font;
		}

		var legacyFont = safeGet("font-family");
		if (typeof legacyFont === "string" && allowedFonts.indexOf(legacyFont) !== -1) {
			return legacyFont;
		}

		for (var i = 0; i < allowedFonts.length; i++) {
			if (document.documentElement.classList.contains(allowedFonts[i])) {
				return allowedFonts[i];
			}
		}

		return "default";
	}

	function applyFontMode(fontClass) {
		var allowedFonts = getAllowedFonts();
		var next = allowedFonts.indexOf(fontClass) !== -1 ? fontClass : "default";

		clearFontClasses();
		if (next !== "default") {
			document.documentElement.classList.add(next);
			safeSet("font-family", next);
		} else {
			safeRemove("font-family");
		}

		return next;
	}

	function getSkinMode() {
		var serverPrefs = getServerPrefs();
		if (serverPrefs && (serverPrefs.skin === "dark" || serverPrefs.skin === "light")) {
			return serverPrefs.skin;
		}

		var appSkin = safeGet("app-skin");
		if (typeof appSkin === "string" && appSkin.indexOf("dark") !== -1) return "dark";

		var appSkinAlt = safeGet("app_skin");
		if (typeof appSkinAlt === "string" && appSkinAlt.indexOf("dark") !== -1) return "dark";

		var theme = safeGet("theme");
		if (typeof theme === "string" && theme.toLowerCase() === "dark") return "dark";

		var legacy = safeGet("app-skin-dark");
		if (typeof legacy === "string" && legacy.indexOf("dark") !== -1) return "dark";

		return document.documentElement.classList.contains("app-skin-dark") ? "dark" : "light";
	}

	function persistSkinMode(mode) {
		var isDark = mode === "dark";
		safeSet("app-skin", isDark ? "app-skin-dark" : "");
		safeSet("app_skin", isDark ? "app-skin-dark" : "");
		safeSet("theme", isDark ? "dark" : "light");
		if (isDark) {
			safeSet("app-skin-dark", "app-skin-dark");
		} else {
			safeRemove("app-skin-dark");
		}
	}

	function getHeaderMode() {
		var serverPrefs = getServerPrefs();
		if (serverPrefs && (serverPrefs.header === "dark" || serverPrefs.header === "light")) {
			return serverPrefs.header;
		}

		var header = safeGet("app-header");
		if (typeof header === "string" && header.indexOf("dark") !== -1) return "dark";
		return document.documentElement.classList.contains("app-header-dark") ? "dark" : "light";
	}

	function getNavigationMode() {
		var serverPrefs = getServerPrefs();
		if (serverPrefs && (serverPrefs.navigation === "dark" || serverPrefs.navigation === "light")) {
			return serverPrefs.navigation;
		}

		var navigation = safeGet("app-navigation");
		if (typeof navigation === "string" && navigation.indexOf("dark") !== -1) return "dark";
		return document.documentElement.classList.contains("app-navigation-dark") ? "dark" : "light";
	}

	function applyNavigationMode(mode) {
		var next = mode === "dark" ? "dark" : "light";
		document.documentElement.classList.toggle("app-navigation-dark", next === "dark");
		safeSet("app-navigation", next === "dark" ? "app-navigation-dark" : "app-navigation-light");

		var navigationLight = document.getElementById("app-navigation-light");
		var navigationDark = document.getElementById("app-navigation-dark");
		if (navigationDark) navigationDark.checked = next === "dark";
		if (navigationLight) navigationLight.checked = next !== "dark";
	}

	function bindNavigationModeInputs() {
		var navigationLight = document.getElementById("app-navigation-light");
		var navigationDark = document.getElementById("app-navigation-dark");

		if (navigationLight) {
			navigationLight.addEventListener("change", function () {
				if (navigationLight.checked) applyNavigationMode("light");
			});
		}

		if (navigationDark) {
			navigationDark.addEventListener("change", function () {
				if (navigationDark.checked) applyNavigationMode("dark");
			});
		}
	}

	function applyHeaderMode(mode) {
		var next = mode === "dark" ? "dark" : "light";
		document.documentElement.classList.toggle("app-header-dark", next === "dark");
		safeSet("app-header", next === "dark" ? "app-header-dark" : "app-header-light");

		var headerLight = document.getElementById("app-header-light");
		var headerDark = document.getElementById("app-header-dark");
		if (headerDark) headerDark.checked = next === "dark";
		if (headerLight) headerLight.checked = next !== "dark";
	}

	function bindHeaderModeInputs() {
		var headerLight = document.getElementById("app-header-light");
		var headerDark = document.getElementById("app-header-dark");

		if (headerLight) {
			headerLight.addEventListener("change", function () {
				if (headerLight.checked) applyHeaderMode("light");
			});
		}

		if (headerDark) {
			headerDark.addEventListener("change", function () {
				if (headerDark.checked) applyHeaderMode("dark");
			});
		}
	}

	function applySkinMode(mode) {
		var isDark = mode === "dark";
		document.documentElement.classList.toggle("app-skin-dark", isDark);
		persistSkinMode(isDark ? "dark" : "light");

		var darkButtons = document.querySelectorAll("a.dark-button,button.dark-button");
		var lightButtons = document.querySelectorAll("a.light-button,button.light-button");
		for (var i = 0; i < darkButtons.length; i++) {
			darkButtons[i].style.display = isDark ? "none" : "";
		}
		for (var j = 0; j < lightButtons.length; j++) {
			lightButtons[j].style.display = isDark ? "" : "none";
		}
	}

	function bindHeaderSkinButtons() {
		var darkButtons = document.querySelectorAll("a.dark-button,button.dark-button");
		var lightButtons = document.querySelectorAll("a.light-button,button.light-button");

		for (var i = 0; i < darkButtons.length; i++) {
			darkButtons[i].addEventListener("click", function (e) {
				e.preventDefault();
				applySkinMode("dark");
			});
		}

		for (var j = 0; j < lightButtons.length; j++) {
			lightButtons[j].addEventListener("click", function (e) {
				e.preventDefault();
				applySkinMode("light");
			});
		}
	}

	function hideLegacyCustomizer() {
		try {
			var styleId = "biotern-legacy-theme-customizer-hidden";
			if (!document.getElementById(styleId)) {
				var style = document.createElement("style");
				style.id = styleId;
				style.textContent = ".theme-customizer,.cutomizer-open-trigger,.customizer-open-trigger{display:none!important;}";
				document.head.appendChild(style);
			}

			var panels = document.querySelectorAll(".theme-customizer");
			for (var i = 0; i < panels.length; i++) {
				panels[i].remove();
			}

			var openers = document.querySelectorAll(".cutomizer-open-trigger,.customizer-open-trigger");
			for (var j = 0; j < openers.length; j++) {
				openers[j].remove();
			}
		} catch (e) {
		}
	}

	function releasePreloadState() {
		try {
			document.documentElement.classList.remove("theme-preload");
			var preloadStyle = document.getElementById("biotern-theme-preload-style");
			if (preloadStyle) {
				preloadStyle.remove();
			}
		} catch (e) {
		}
	}

	function initThemeRuntime() {
		applyFontMode(getFontMode());
		applySkinMode(getSkinMode());
		applyNavigationMode(getNavigationMode());
		applyHeaderMode(getHeaderMode());
		bindHeaderSkinButtons();
		bindNavigationModeInputs();
		bindHeaderModeInputs();
		hideLegacyCustomizer();
		releasePreloadState();
	}

	if (document.readyState === "loading") {
		document.addEventListener("DOMContentLoaded", initThemeRuntime);
	} else {
		initThemeRuntime();
	}
})();
